// Summary: Checks ToggleGroup group labeling, item count, value-derived aria labels, decorative icons, and radio rendering for provided items.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { ToggleGroup } from './ToggleGroup';
import type { ToggleGroupProps } from './ToggleGroup';

const baseItems: ToggleGroupProps['items'] = [
  { value: 'left', icon: <span data-testid="left-icon">L</span>, ariaLabel: 'Align left' },
  { value: 'center', icon: <span data-testid="center-icon">C</span>, ariaLabel: 'Align center' },
  { value: 'right', icon: <span data-testid="right-icon">R</span> }
];

describe('ToggleGroup', () => {
  it('renders the group with the provided ariaLabel', () => {
    render(
      <ToggleGroup ariaLabel="Text alignment" type="single" defaultValue="left" items={baseItems} />
    );
    expect(screen.getByRole('group', { name: 'Text alignment' })).toBeInTheDocument();
  });

  it('renders the expected number of toggle items', () => {
    render(
      <ToggleGroup ariaLabel="Text alignment" type="single" defaultValue="left" items={baseItems} />
    );
    expect(screen.getAllByRole('radio')).toHaveLength(3);
  });

  it('derives aria-label from item value when ariaLabel is omitted', () => {
    render(
      <ToggleGroup ariaLabel="Text alignment" type="single" defaultValue="left" items={baseItems} />
    );
    expect(screen.getByRole('radio', { name: 'right' })).toBeInTheDocument();
  });

  it('hides the item icon from assistive technology', () => {
    render(
      <ToggleGroup ariaLabel="Text alignment" type="single" defaultValue="left" items={baseItems} />
    );
    const button = screen.getByRole('radio', { name: 'Align left' });
    expect(button.querySelector('[aria-hidden="true"]')).not.toBeNull();
  });
});
